def normalize_offer(offer: Any) -> Optional[Dict[str, int]]:
    if not isinstance(offer, dict):
        return None
    out: Dict[str, int] = {}
    for k, v in offer.items():
        if not isinstance(k, str):
            return None
        if not isinstance(v, int):
            return None
        if v <= 0:
            return None
        if len(k) > 64:
            return None
        out[k] = out.get(k, 0) + v
    if not out:
        return None
    return out


def inv_has(inv: Dict[str, int], template: str, qty: int) -> bool:
    return inv.get(template, 0) >= qty


def inv_add(inv: Dict[str, int], template: str, qty: int) -> None:
    inv[template] = inv.get(template, 0) + qty
    if inv[template] <= 0:
        inv.pop(template, None)


def inv_sub(inv: Dict[str, int], template: str, qty: int) -> bool:
    if inv.get(template, 0) < qty:
        return False
    inv[template] -= qty
    if inv[template] <= 0:
        inv.pop(template, None)
    return True


