async def finalize_trade(trade_id: str) -> None:
    async with STATE._trade_lock:
        t = STATE.trades.get(trade_id)
        if not t or t.status != "open":
            return
        a_id, b_id = t.a_id, t.b_id
        a_offer = dict(t.a_offer)
        b_offer = dict(t.b_offer)

    l1, l2 = await with_two_player_locks(a_id, b_id)
    try:
        a = STATE.get_player(a_id)
        b = STATE.get_player(b_id)
        if not a or not b:
            async with STATE._trade_lock:
                t2 = STATE.trades.get(trade_id)
                if t2 and t2.status == "open":
                    t2.status = "cancelled"
                    t2.updated_ms = now_ms()
                    snap = trade_snapshot(t2)
            await STATE.broadcast({a_id, b_id}, {"type": "trade_update", "trade": snap})
            return

        for template, qty in a_offer.items():
            if not inv_has(a.inventory, template, qty):
                async with STATE._trade_lock:
                    t2 = STATE.trades.get(trade_id)
                    if t2 and t2.status == "open":
                        t2.status = "cancelled"
                        t2.updated_ms = now_ms()
                        snap = trade_snapshot(t2)
                await STATE.broadcast({a_id, b_id}, {"type": "trade_failed", "trade_id": trade_id, "reason": "insufficient_items", "who": a_id})
                await STATE.broadcast({a_id, b_id}, {"type": "trade_update", "trade": snap})
                return

        for template, qty in b_offer.items():
            if not inv_has(b.inventory, template, qty):
                async with STATE._trade_lock:
                    t2 = STATE.trades.get(trade_id)
                    if t2 and t2.status == "open":
                        t2.status = "cancelled"
                        t2.updated_ms = now_ms()
                        snap = trade_snapshot(t2)
                await STATE.broadcast({a_id, b_id}, {"type": "trade_failed", "trade_id": trade_id, "reason": "insufficient_items", "who": b_id})
                await STATE.broadcast({a_id, b_id}, {"type": "trade_update", "trade": snap})
                return

        for template, qty in a_offer.items():
            inv_sub(a.inventory, template, qty)
        for template, qty in b_offer.items():
            inv_sub(b.inventory, template, qty)

        for template, qty in a_offer.items():
            inv_add(b.inventory, template, qty)
        for template, qty in b_offer.items():
            inv_add(a.inventory, template, qty)

        async with STATE._trade_lock:
            t2 = STATE.trades.get(trade_id)
            if t2 and t2.status == "open":
                t2.status = "completed"
                t2.updated_ms = now_ms()
                snap = trade_snapshot(t2)
            else:
                snap = trade_snapshot(t) if t else {"trade_id": trade_id, "status": "unknown"}

    finally:
        release_two_locks(l1, l2)

    await STATE.broadcast({a_id, b_id}, {"type": "trade_complete", "trade": snap})
    await STATE.send_to_player(a_id, {"type": "inventory_update", "inventory": dict(STATE.players[a_id].inventory)})
    await STATE.send_to_player(b_id, {"type": "inventory_update", "inventory": dict(STATE.players[b_id].inventory)})


async def handle_transfer_direct(ws: WebSocketServerProtocol, player_id: str, msg: Dict[str, Any]) -> None:
    req_id = msg.get("req_id")
    to_id = msg.get("to_id")
    template = msg.get("template")
    qty = msg.get("qty")

    if not isinstance(to_id, str) or len(to_id) > 64 or not to_id:
        await STATE.send(ws, err(req_id, "bad_request", "invalid to_id"))
        return
    if to_id == player_id:
        await STATE.send(ws, err(req_id, "bad_request", "cannot transfer to self"))
        return
    if not isinstance(template, str) or len(template) > 64 or not template:
        await STATE.send(ws, err(req_id, "bad_request", "invalid template"))
        return
    if not isinstance(qty, int) or qty <= 0 or qty > 10_000_000:
        await STATE.send(ws, err(req_id, "bad_request", "invalid qty"))
        return

    if not STATE.get_player(to_id):
        STATE.ensure_player(to_id, name=to_id)

    l1, l2 = await with_two_player_locks(player_id, to_id)
    try:
        src = STATE.get_player(player_id)
        dst = STATE.get_player(to_id)
        if not src or not dst:
            await STATE.send(ws, err(req_id, "not_found", "player not found"))
            return
        if not inv_sub(src.inventory, template, qty):
            await STATE.send(ws, err(req_id, "insufficient_items", "not enough items"))
            return
        inv_add(dst.inventory, template, qty)
    finally:
        release_two_locks(l1, l2)

    await STATE.send(ws, ok(req_id, from_id=player_id, to_id=to_id, template=template, qty=qty))
    await STATE.send_to_player(player_id, {"type": "inventory_update", "inventory": dict(STATE.players[player_id].inventory)})
    await STATE.send_to_player(to_id, {"type": "inventory_update", "inventory": dict(STATE.players[to_id].inventory)})


async def route(ws: WebSocketServerProtocol, msg: Dict[str, Any]) -> None:
    mtype = msg.get("type")
    if not isinstance(mtype, str):
        await STATE.send(ws, err(msg.get("req_id"), "bad_request", "missing type"))
        return

    if mtype == "login":
        await handle_login(ws, msg)
        return

    player_id = STATE.ws_to_player.get(ws)
    if not player_id:
        await STATE.send(ws, err(msg.get("req_id"), "unauthorized", "login required"))
        return

    p = STATE.get_player(player_id)
    if p:
        p.last_seen_ms = now_ms()

    if mtype == "inventory_get":
        await handle_inventory_get(ws, player_id, msg)
    elif mtype == "trade_create":
        await handle_trade_create(ws, player_id, msg)
    elif mtype == "trade_offer":
        await handle_trade_offer(ws, player_id, msg)
    elif mtype == "trade_accept":
        await handle_trade_accept(ws, player_id, msg)
    elif mtype == "trade_cancel":
        await handle_trade_cancel(ws, player_id, msg)
    elif mtype == "transfer":
        await handle_transfer_direct(ws, player_id, msg)
    else:
        await STATE.send(ws, err(msg.get("req_id"), "bad_request", f"unknown type: {mtype}"))


async def client_handler(ws: WebSocketServerProtocol) -> None:
    try:
        async for raw in ws:
            if isinstance(raw, bytes):
                if len(raw) > MAX_MSG_BYTES:
                    await ws.close(code=1009, reason="Message too big")
                    return
                try:
                    raw = raw.decode("utf-8")
                except Exception:
                    await STATE.send(ws, err(None, "bad_request", "invalid utf-8"))
                    continue
            if not isinstance(raw, str):
                continue
            if len(raw) > MAX_MSG_BYTES:
                await ws.close(code=1009, reason="Message too big")
                return
            try:
                msg = jload(raw)
            except Exception:
                await STATE.send(ws, err(None, "bad_request", "invalid json"))
                continue
            if not isinstance(msg, dict):
                await STATE.send(ws, err(None, "bad_request", "json must be object"))
                continue
            await route(ws, msg)
    except websockets.ConnectionClosed:
        pass
    finally:
        pid = STATE.ws_to_player.pop(ws, None)
        if pid:
            p = STATE.get_player(pid)
            if p and p.ws == ws:
                p.connected = False
                p.ws = None
                p.last_seen_ms = now_ms()


async def main(host: str = "0.0.0.0", port: int = 8765) -> None:
    async with websockets.serve(
        client_handler,
        host,
        port,
        max_size=MAX_MSG_BYTES,
        ping_interval=PING_INTERVAL,
        ping_timeout=PING_TIMEOUT,
    ):
        logging.info("MMO server listening on %s:%d", host, port)
        while True:
            await asyncio.sleep(3600)


